// Ternary operator ilə içki seçimi
let temperature = 15;
let drink = temperature < 20 ? "İsti çay iç!" : "Meyvə şirəsi iç!";
console.log(drink); // nəticə: İsti çay iç!

// Ternary operator ilə yaş yoxlaması
let age = 20;
let message = age >= 18 ? "Sən böyüksən!" : "Sən kiçiksən!";
console.log(message); // nəticə: Sən böyüksən!

// Ternary operator ilə dəyişənə təyinat
let temperature = 25;
let drink = temperature < 20 ? "İsti çay" : "Meyvə şirəsi";
console.log("Bugün sən " + drink + " içəcəksən!"); // nəticə: Bugün sən Meyvə şirəsi içəcəksən!

// Ternary operator ilə
let temperature = 15;
let drink = temperature < 20 ? "İsti çay iç!" : "Meyvə şirəsi iç!";
console.log(drink); // nəticə: İsti çay iç!

// Eyni tapşırıq if...else ilə
if (temperature < 20) {
  console.log("İsti çay iç!");
} else {
  console.log("Meyvə şirəsi iç!");
}
// nəticə: İsti çay iç!

// Mürəkkəb ternary operator (tövsiyə olunmur)
let temperature = 25;
let drink = temperature < 20 ? "İsti çay" : temperature < 30 ? "Su" : "Meyvə şirəsi";
console.log(drink); // nəticə: Su

// Eyni tapşırıq if...else ilə (daha oxunaqlı)
if (temperature < 20) {
  console.log("İsti çay");
} else if (temperature < 30) {
  console.log("Su");
} else {
  console.log("Meyvə şirəsi");
}
// nəticə: Su

