// Ternary operator for drink choice
let temperature = 15;
let drink = temperature < 20 ? "Drink hot tea!" : "Drink fruit juice!";
console.log(drink); // Output: Drink hot tea!

// Ternary operator for age check
let age = 20;
let message = age >= 18 ? "You’re an adult!" : "You’re a minor!";
console.log(message); // Output: You’re an adult!

// Ternary operator for variable assignment
let temperature = 25;
let drink = temperature < 20 ? "Hot tea" : "Fruit juice";
console.log("Today you’ll drink " + drink + "!"); // Output: Today you’ll drink Fruit juice!

// Ternary operator
let temperature = 15;
let drink = temperature < 20 ? "Drink hot tea!" : "Drink fruit juice!";
console.log(drink); // Output: Drink hot tea!

// Same task with if...else
if (temperature < 20) {
  console.log("Drink hot tea!");
} else {
  console.log("Drink fruit juice!");
}
// Output: Drink hot tea!

// Complex ternary operator (not recommended)
let temperature = 25;
let drink = temperature < 20 ? "Hot tea" : temperature < 30 ? "Water" : "Fruit juice";
console.log(drink); // Output: Water

// Same task with if...else (more readable)
if (temperature < 20) {
  console.log("Hot tea");
} else if (temperature < 30) {
  console.log("Water");
} else {
  console.log("Fruit juice");
}
// Output: Water

