// Тернарный оператор для выбора напитка
let temperature = 15;
let drink = temperature < 20 ? "Пей горячий чай!" : "Пей фруктовый сок!";
console.log(drink); // Вывод: Пей горячий чай!

// Тернарный оператор для проверки возраста
let age = 20;
let message = age >= 18 ? "Ты взрослый!" : "Ты несовершеннолетний!";
console.log(message); // Вывод: Ты взрослый!

// Тернарный оператор для присваивания переменной
let temperature = 25;
let drink = temperature < 20 ? "Горячий чай" : "Фруктовый сок";
console.log("Сегодня ты будешь пить " + drink + "!"); // Вывод: Сегодня ты будешь пить Фруктовый сок!

// Тернарный оператор
let temperature = 15;
let drink = temperature < 20 ? "Пей горячий чай!" : "Пей фруктовый сок!";
console.log(drink); // Вывод: Пей горячий чай!

// Та же задача с if...else
if (temperature < 20) {
  console.log("Пей горячий чай!");
} else {
  console.log("Пей фруктовый сок!");
}
// Вывод: Пей горячий чай!

// Сложный тернарный оператор (не рекомендуется)
let temperature = 25;
let drink = temperature < 20 ? "Горячий чай" : temperature < 30 ? "Вода" : "Фруктовый сок";
console.log(drink); // Вывод: Вода

// Та же задача с if...else (более читаемо)
if (temperature < 20) {
  console.log("Горячий чай");
} else if (temperature < 30) {
  console.log("Вода");
} else {
  console.log("Фруктовый сок");
}
// Вывод: Вода

